   import java.io.BufferedWriter;
  import java.io.FileInputStream;
  import java.io.FileNotFoundException;
  import java.io.FileWriter;
  import java.io.IOException;

  public void logToFile(Object content, String tag){
    BufferedWriter writer = null;
    try {
      writer = new BufferedWriter( new FileWriter(tag,true));
      writer.append( content);
      writer.newLine();
      writer.flush();
    }catch ( IOException e){
      log.error(e);
    }finally {
      try{
        if ( writer != null){ 
          writer.close( );
        }
      }catch ( IOException e) {
        log.error(e);
      }
    }

  }
